3_real_world_example.code:
const role = 'admin';

switch (role) {
  case 'admin':
    console.log('Full Access Granted');
    break;
  case 'editor':
    console.log('Edit Access Granted');
    break;
  case 'viewer':
    console.log('Read-Only Access');
    break;
  default:
    console.log('Access Denied');
}

